const body = $input.first().json.body ?? $input.first().json;
const { material_id, raw_text, title, enabled_personas, enable_av_output } = body;

const words = raw_text.split(/\s+/);
const chunkSize = 300;
const chunks = [];
for (let i = 0; i < words.length; i += chunkSize) {
  chunks.push(words.slice(i, i + chunkSize).join(' '));
}
const limited = chunks.slice(0, 5);

const allPersonaSlugs = ['lecture-bestie', 'exam-gremlin', 'problem-grinder', 'doodle-prof', 'meme-lord', 'study-bard'];
const allPostTypes    = ['concept', 'trap', 'example', 'concept', 'example', 'recap'];

const activePersonas = Array.isArray(enabled_personas) && enabled_personas.length > 0
  ? enabled_personas.filter(s => allPersonaSlugs.includes(s))
  : allPersonaSlugs;

const imagePrimaryPersonas = new Set(['doodle-prof', 'meme-lord']);
const audioPrimaryPersonas = new Set(['study-bard']);
const otherMediaTypesAV    = ['text', 'video', 'text', 'image'];
const otherMediaTypesNoAV  = ['text', 'image'];

const items = [];
for (let ci = 0; ci < limited.length; ci++) {
  for (let pi = 0; pi < activePersonas.length; pi++) {
    const personaSlug = activePersonas[pi];
    const origIndex   = allPersonaSlugs.indexOf(personaSlug);
    let mediaType;
    if (imagePrimaryPersonas.has(personaSlug)) {
      mediaType = 'image';
    } else if (audioPrimaryPersonas.has(personaSlug)) {
      mediaType = enable_av_output !== false ? 'audio' : 'text';
    } else if (enable_av_output !== false) {
      mediaType = otherMediaTypesAV[ci % otherMediaTypesAV.length];
    } else {
      mediaType = otherMediaTypesNoAV[ci % otherMediaTypesNoAV.length];
    }
    items.push({
      material_id,
      title,
      chunk_text: limited[ci],
      chunk_index: ci,
      persona_slug: personaSlug,
      post_type: allPostTypes[origIndex] ?? 'concept',
      media_type: mediaType,
    });
  }
}

return items.map(item => ({ json: item }));

const allChunks   = $('Split into chunks').all();
const allPersonas = $input.all();

const items = [];
for (let i = 0; i < allPersonas.length; i++) {
  const chunk      = allChunks[i].json;
  const personaRaw = allPersonas[i].json;
  const persona    = Array.isArray(personaRaw) ? personaRaw[0] : personaRaw;

  if (!persona || !persona.id) continue;

  const userPrompt = `Here is a section of study material titled "${chunk.title}":\n\n${chunk.chunk_text}\n\nGenerate one educational post about the main concept in this section. Return ONLY valid JSON with fields "title" and "body".`;

  items.push({
    json: {
      ...chunk,
      persona_id:    persona.id,
      persona_name:  persona.name,
      system_prompt: persona.system_prompt,
      user_prompt:   userPrompt,
    }
  });
}

return items;
